.darma-loader-loading-io-24 {
      position: relative;
      display: inline-block;
      width: 64px;
      height: 64px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color, #ec4899) 24%, transparent);
    }
    .darma-loader-loading-io-24 i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: darma-loader-loading-io-24-orbit 0.9s linear infinite;
    }
    .darma-loader-loading-io-24 i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color, #ec4899);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color, #ec4899) 45%, transparent);
    }
    .darma-loader-loading-io-24 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-24 i:nth-child(2) { animation-delay: -0.45s; }
    @keyframes darma-loader-loading-io-24-orbit { to { transform: rotate(360deg); } }

